#!/usr/bin/env python
"""
Bootstrap: Capture-Transform Orchestration Wiring
REQUIRES: All 5 prior bootstraps run first.
Writes adapters/capture_transform_adapter.py
        conversation/decomposer_capture_transform.py
        tests/test_capture_transform_orchestration.py
Run: python bootstrap_capture_transform_orchestration.py
"""
import base64, os, sys

if os.path.exists("core/universal_schema.py"): root = "."
elif os.path.exists("../core/universal_schema.py"): root = ".."
else: print("ERROR: Run from MABE root or one dir below."); sys.exit(1)

deps = ["core/transform_enumerator.py", "core/substrate_anchor.py",
        "core/capture_transform_scorer.py", "core/cascade_scaffold.py",
        "core/capture_transform_pipeline.py"]
for d in deps:
    if not os.path.exists(os.path.join(root, d)):
        print(f"ERROR: {d} not found. Run prior bootstraps first.")
        sys.exit(1)

_p = os.path.join(root, "adapters/capture_transform_adapter.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

_p = os.path.join(root, "conversation/decomposer_capture_transform.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

_p = os.path.join(root, "tests/test_capture_transform_orchestration.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

print("Done. Run: python -m pytest tests/test_capture_transform_orchestration.py -v")